// frontend/src/components/vouchers/VoucherPurchase.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './Voucher.css';

const VoucherPurchase = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [templates, setTemplates] = useState([]);
    const [selectedTemplate, setSelectedTemplate] = useState(null);
    const [quantity, setQuantity] = useState(1);
    const [paymentMethod, setPaymentMethod] = useState('cash');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    useEffect(() => {
        loadTemplates();
    }, []);

    const loadTemplates = async () => {
        try {
            const response = await api.get('/vouchers/templates');
            if (response.data.success) {
                setTemplates(response.data.data);
                if (response.data.data.length > 0) {
                    setSelectedTemplate(response.data.data[0]);
                }
            }
        } catch (error) {
            console.error('Error loading templates:', error);
        }
    };

    const handlePurchase = async () => {
        if (!selectedTemplate) {
            setError('Please select a voucher type');
            return;
        }

        setLoading(true);
        setError('');
        setSuccess('');

        try {
            const response = await api.post('/vouchers/purchase', {
                template_id: selectedTemplate.id,
                quantity,
                payment_method: paymentMethod
            });

            if (response.data.success) {
                setSuccess(`Successfully purchased ${quantity} voucher(s)!`);
                setTimeout(() => {
                    navigate('/vouchers/my');
                }, 2000);
            } else {
                setError(response.data.message || 'Purchase failed');
            }
        } catch (error) {
            console.error('Purchase error:', error);
            setError('Network error. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const calculateTotal = () => {
        if (!selectedTemplate) return 0;
        return selectedTemplate.selling_price * quantity;
    };

    return (
        <div className="voucher-container">
            <div className="voucher-card">
                <div className="voucher-header">
                    <h2>🎫 Buy Vouchers</h2>
                    <p>Pay for jobs securely with vouchers</p>
                </div>

                {error && <div className="voucher-error">{error}</div>}
                {success && <div className="voucher-success">{success}</div>}

                <div className="voucher-templates">
                    <h3>Select Voucher Type</h3>
                    <div className="templates-grid">
                        {templates.map(template => (
                            <div
                                key={template.id}
                                className={`template-card ${selectedTemplate?.id === template.id ? 'selected' : ''}`}
                                onClick={() => setSelectedTemplate(template)}
                            >
                                <div className="template-value">R {template.face_value}</div>
                                <div className="template-price">Pay: R {template.selling_price}</div>
                                <div className="template-name">{template.name}</div>
                                <div className="template-save">
                                    Save R {template.face_value - template.selling_value}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {selectedTemplate && (
                    <div className="voucher-details">
                        <h3>Voucher Details</h3>
                        <p className="template-description">{selectedTemplate.description}</p>

                        <div className="detail-row">
                            <span>Face Value:</span>
                            <span className="value">R {selectedTemplate.face_value}</span>
                        </div>
                        <div className="detail-row">
                            <span>Price:</span>
                            <span className="value">R {selectedTemplate.selling_price}</span>
                        </div>
                        <div className="detail-row">
                            <span>Valid for:</span>
                            <span className="value">{selectedTemplate.validity_days} days</span>
                        </div>
                    </div>
                )}

                <div className="purchase-form">
                    <h3>Purchase Details</h3>

                    <div className="form-group">
                        <label>Quantity</label>
                        <input
                            type="number"
                            min="1"
                            max="10"
                            value={quantity}
                            onChange={(e) => setQuantity(parseInt(e.target.value) || 1)}
                        />
                    </div>

                    <div className="form-group">
                        <label>Payment Method</label>
                        <select 
                            value={paymentMethod}
                            onChange={(e) => setPaymentMethod(e.target.value)}
                        >
                            <option value="cash">Cash (Pay at partner shop)</option>
                            <option value="eft">EFT / Bank Transfer</option>
                            <option value="mobile_money">Mobile Money</option>
                        </select>
                    </div>

                    <div className="total-section">
                        <span>Total Amount:</span>
                        <span className="total-amount">R {calculateTotal()}</span>
                    </div>

                    <button
                        className="purchase-button"
                        onClick={handlePurchase}
                        disabled={loading || !selectedTemplate}
                    >
                        {loading ? 'Processing...' : '💳 Purchase Vouchers'}
                    </button>
                </div>

                <div className="voucher-info">
                    <h4>💡 How Vouchers Work</h4>
                    <ul>
                        <li>Buy vouchers and pay for jobs securely</li>
                        <li>Each voucher has a unique code and PIN</li>
                        <li>Use balance in app or via USSD (*130*469#)</li>
                        <li>Valid for {selectedTemplate?.validity_days || 365} days</li>
                        <li>Can be split across multiple jobs</li>
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default VoucherPurchase;
